const payload = {
  linear_ticket_id: input.issueIdentifier,
  linear_issue_id: input.issueId,
  linear_url: input.issueUrl,
  app_id: input.appLabel,
  title: input.issueTitle,
  description: input.issueDescription,
  labels: input.allLabels,
